[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;

    private static readonly HashSet<string> AllowedImageExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".svg", ".ico", ".tiff", ".tif"
    };

    private static readonly HashSet<string> AllowedDocumentExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx",
        ".odt", ".ods", ".odp", ".txt", ".rtf", ".csv"
    };

    private static readonly HashSet<string> AllowedAvatarExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".jpg", ".jpeg", ".png", ".gif", ".webp"
    };

    private static readonly Dictionary<string, List<byte[]>> FileSignatures = new()
    {
        { ".jpg", new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } } },
        { ".jpeg", new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } } },
        { ".png", new List<byte[]> { new byte[] { 0x89, 0x50, 0x4E, 0x47 } } },
        { ".gif", new List<byte[]> { new byte[] { 0x47, 0x49, 0x46 } } },
        { ".pdf", new List<byte[]> { new byte[] { 0x25, 0x50, 0x44, 0x46 } } },
        { ".bmp", new List<byte[]> { new byte[] { 0x42, 0x4D } } },
        { ".zip", new List<byte[]> { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
    };

    private const long MaxAvatarSize = 5 * 1024 * 1024; // 5 MB
    private const long MaxDocumentSize = 50 * 1024 * 1024; // 50 MB

    public FileUploadController(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file provided or file is empty."
            });
        }

        if (file.Length > MaxAvatarSize)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File size exceeds the maximum allowed size of {MaxAvatarSize / (1024 * 1024)} MB."
            });
        }

        var extension = Path.GetExtension(file.FileName);

        if (!AllowedAvatarExtensions.Contains(extension))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File type '{extension}' is not allowed for avatars. Allowed types: {string.Join(", ", AllowedAvatarExtensions)}"
            });
        }

        if (!await ValidateFileSignature(file, extension))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "File content does not match the file extension."
            });
        }

        var result = await SaveFileAsync(file, "avatars");
        return Ok(result);
    }

    [HttpPost("document")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file provided or file is empty."
            });
        }

        if (file.Length > MaxDocumentSize)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File size exceeds the maximum allowed size of {MaxDocumentSize / (1024 * 1024)} MB."
            });
        }

        var extension = Path.GetExtension(file.FileName);

        if (!AllowedDocumentExtensions.Contains(extension) && !AllowedImageExtensions.Contains(extension))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File type '{extension}' is not allowed. Allowed types: {string.Join(", ", AllowedDocumentExtensions.Union(AllowedImageExtensions))}"
            });
        }

        if (!await ValidateFileSignature(file, extension))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "File content does not match the file extension."
            });
        }

        var result = await SaveFileAsync(file, "documents");
        return Ok(result);
    }

    [HttpPost("documents")]
    [RequestSizeLimit(200 * 1024 * 1024)]
    public async Task<IActionResult> UploadMultipleDocuments(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new MultiFileUploadResult
            {
                Success = false
            });
        }

        var result = new MultiFileUploadResult();

        foreach (var file in files)
        {
            if (file.Length == 0)
            {
                result.Files.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = "File is empty."
                });
                result.TotalFailed++;
                continue;
            }

            if (file.Length > MaxDocumentSize)
            {
                result.Files.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = $"File size exceeds the maximum allowed size of {MaxDocumentSize / (1024 * 1024)} MB."
                });
                result.TotalFailed++;
                continue;
            }

            var extension = Path.GetExtension(file.FileName);

            if (!AllowedDocumentExtensions.Contains(extension) && !AllowedImageExtensions.Contains(extension))
            {
                result.Files.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = $"File type '{extension}' is not allowed."
                });
                result.TotalFailed++;
                continue;
            }

            if (!await ValidateFileSignature(file, extension))
            {
                result.Files.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = "File content does not match the file extension."
                });
                result.TotalFailed++;
                continue;
            }

            var uploadResult = await SaveFileAsync(file, "documents");
            result.Files.Add(uploadResult);

            if (uploadResult.Success)
                result.TotalUploaded++;
            else
                result.TotalFailed++;
        }

        result.Success = result.TotalUploaded > 0;
        return Ok(result);
    }

    [HttpDelete]
    public IActionResult DeleteFile([FromQuery] string filePath)
    {
        if (string.IsNullOrWhiteSpace(filePath))
        {
            return BadRequest("File path is required.");
        }

        // Sanitize path to prevent directory traversal
        var sanitizedPath = filePath.Replace("..", "").TrimStart('/').TrimStart('\\');
        var fullPath = Path.Combine(_environment.WebRootPath, sanitizedPath);

        // Ensure the path is within wwwroot/uploads
        var uploadsRoot = Path.Combine(_environment.WebRootPath, "uploads");
        var resolvedPath = Path.GetFullPath(fullPath);

        if (!resolvedPath.StartsWith(Path.GetFullPath(uploadsRoot)))
        {
            return BadRequest("Invalid file path.");
        }

        if (!System.IO.File.Exists(fullPath))
        {
            return NotFound("File not found.");
        }

        System.IO.File.Delete(fullPath);
        return Ok(new { Success = true, Message = "File deleted successfully." });
    }

    private async Task<FileUploadResult> SaveFileAsync(IFormFile file, string subfolder)
    {
        try
        {
            var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads", subfolder);

            if (!Directory.Exists(uploadsFolder))
            {
                Directory.CreateDirectory(uploadsFolder);
            }

            var extension = Path.GetExtension(file.FileName);
            var sanitizedOriginalName = SanitizeFileName(Path.GetFileNameWithoutExtension(file.FileName));
            var uniqueFileName = $"{sanitizedOriginalName}_{Guid.NewGuid():N}{extension}";
            var filePath = Path.Combine(uploadsFolder, uniqueFileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = Path.Combine("uploads", subfolder, uniqueFileName).Replace("\\", "/");

            return new FileUploadResult
            {
                Success = true,
                FilePath = $"/{relativePath}",
                FileName = uniqueFileName,
                FileSize = file.Length,
                ContentType = file.ContentType
            };
        }
        catch (Exception ex)
        {
            return new FileUploadResult
            {
                Success = false,
                FileName = file.FileName,
                ErrorMessage = $"An error occurred while uploading the file: {ex.Message}"
            };
        }
    }

    private static string SanitizeFileName(string fileName)
    {
        var invalidChars = Path.GetInvalidFileNameChars();
        var sanitized = new string(fileName
            .Where(c => !invalidChars.Contains(c))
            .ToArray());

        sanitized = sanitized.Replace(" ", "_");

        if (sanitized.Length > 50)
            sanitized = sanitized[..50];

        if (string.IsNullOrWhiteSpace(sanitized))
            sanitized = "file";

        return sanitized;
    }

    private static async Task<bool> ValidateFileSignature(IFormFile file, string extension)
    {
        var ext = extension.ToLowerInvariant();

        if (!FileSignatures.ContainsKey(ext))
        {
            // If we don't have a signature to check, allow it (for office docs, txt, csv, etc.)
            return true;
        }

        using var reader = new BinaryReader(file.OpenReadStream());
        var signatures = FileSignatures[ext];
        var headerBytes = reader.ReadBytes(signatures.Max(s => s.Length));

        // Reset the stream position
        file.OpenReadStream().Position = 0;

        return signatures.Any(signature =>
            headerBytes.Length >= signature.Length &&
            headerBytes.Take(signature.Length).SequenceEqual(signature));
    }
}